// @ts-nocheck
export function formatPrice(e){return Number(e).toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g," ")}export function formatDate(e){if(!e)return"";const t=new Date(e),o=new Date-t,r=Math.floor(o/864e5);return 0===r?"Сегодня, "+t.toLocaleTimeString("ru-RU",{hour:"2-digit",minute:"2-digit"}):1===r?"Вчера, "+t.toLocaleTimeString("ru-RU",{hour:"2-digit",minute:"2-digit"}):r<7?r+" дн. назад":t.toLocaleDateString("ru-RU",{day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit"})}export function getCsrfToken(){const e=document.querySelector('meta[name="csrf-token"]');if(e){return e.getAttribute("content")}const t=getCookie("XSRF-TOKEN");if(t){const e=decodeURIComponent(t);return console.log("CSRF token from cookie:",e),e}return console.log("No CSRF token found"),null}function getCookie(e){const t=`; ${document.cookie}`.split(`; ${e}=`);return 2===t.length?t.pop().split(";").shift():null}export function handleApiError(e){return e.message&&!e.message.includes("HTTP error!")?e.message:e.response?.data?.message?e.response.data.message:"Network Error"===e.message?"Ошибка сети. Проверьте подключение к интернету.":e.message?.includes("HTTP error!")?"Ошибка сервера. Попробуйте позже.":e.message||"Произошла неизвестная ошибка. Попробуйте позже."}